#!/usr/bin/env python3
import subprocess
import sys
import os
import shutil
import hashlib
import json
from pathlib import Path
from datetime import datetime

def run_command(cmd, check=True, capture_output=False):
    result = subprocess.run(
        cmd,
        shell=isinstance(cmd, str),
        check=check,
        capture_output=capture_output,
        text=True
    )
    return result

def verify_requirements_hash():
    req_file = Path('requirements.txt')
    if not req_file.exists():
        print("ERROR: requirements.txt not found")
        sys.exit(1)
    
    with open(req_file, 'rb') as f:
        req_hash = hashlib.sha256(f.read()).hexdigest()
    
    hash_file = Path('.requirements.hash')
    if hash_file.exists():
        with open(hash_file, 'r') as f:
            stored_hash = f.read().strip()
        if stored_hash == req_hash:
            return False
    
    with open(hash_file, 'w') as f:
        f.write(req_hash)
    return True

def install_dependencies():
    print("=== Installing Dependencies ===")
    
    needs_install = verify_requirements_hash()
    
    pip_cmd = [
        sys.executable, '-m', 'pip', 'install',
        '--upgrade',
        '--require-hashes' if os.path.exists('requirements.txt') and '--hash' in open('requirements.txt').read() else '--no-deps',
        '-r', 'requirements.txt'
    ]
    
    if '--no-deps' in pip_cmd:
        pip_cmd.remove('--no-deps')
    
    pip_cmd = [sys.executable, '-m', 'pip', 'install', '--upgrade', '-r', 'requirements.txt']
    
    run_command(pip_cmd)
    
    run_command([sys.executable, '-m', 'pip', 'check'])
    
    result = run_command(
        [sys.executable, '-m', 'pip', 'list', '--outdated', '--format=json'],
        capture_output=True
    )
    
    if result.stdout.strip() and result.stdout.strip() != '[]':
        outdated = json.loads(result.stdout)
        if outdated:
            print("\nWARNING: Outdated packages detected:")
            for pkg in outdated:
                print(f"  {pkg['name']}: {pkg['version']} -> {pkg['latest_version']}")
            
            if os.getenv('CI_STRICT_DEPS', 'false').lower() == 'true':
                print("\nERROR: Outdated dependencies not allowed in strict mode")
                sys.exit(1)
    
    print("Dependencies installed successfully\n")

def run_tests():
    print("=== Running Tests ===")
    
    test_runners = [
        (['pytest', '-v', '--tb=short'], 'pytest'),
        (['python', '-m', 'unittest', 'discover', '-s', 'tests', '-v'], 'unittest'),
        (['python', '-m', 'pytest'], 'pytest-module'),
        (['python', 'tests/run_tests.py'], 'custom'),
    ]
    
    for cmd, runner_name in test_runners:
        result = run_command(cmd, check=False, capture_output=True)
        if result.returncode == 0:
            print(f"Tests passed using {runner_name}")
            print(result.stdout)
            return
        elif 'No module named' not in result.stderr and 'not found' not in result.stderr:
            print(f"Tests failed using {runner_name}")
            print(result.stdout)
            print(result.stderr, file=sys.stderr)
            sys.exit(1)
    
    print("WARNING: No test runner found, skipping tests")

def package_deployment():
    print("\n=== Packaging for Deployment ===")
    
    dist_dir = Path('dist')
    if dist_dir.exists():
        shutil.rmtree(dist_dir)
    dist_dir.mkdir()
    
    build_dir = Path('build')
    if build_dir.exists():
        shutil.rmtree(build_dir)
    
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    version = os.getenv('CI_BUILD_VERSION', '1.0.0')
    
    package_name = f"deployment_{version}_{timestamp}"
    package_path = dist_dir / package_name
    package_path.mkdir()
    
    exclude_patterns = {
        '__pycache__', '*.pyc', '*.pyo', '.git', '.gitignore',
        'tests', 'test_*', '.pytest_cache', '.coverage', 
        'venv', 'env', '.env', 'dist', 'build', '*.egg-info',
        '.tox', '.mypy_cache', '.vscode', '.idea', 'node_modules'
    }
    
    def should_exclude(path):
        parts = Path(path).parts
        for pattern in exclude_patterns:
            if pattern.startswith('*'):
                if any(str(p).endswith(pattern[1:]) for p in parts):
                    return True
            elif any(pattern in str(p) for p in parts):
                return True
        return False
    
    for item in Path('.').iterdir():
        if item.name in exclude_patterns or should_exclude(item):
            continue
        
        dest = package_path / item.name
        if item.is_dir():
            shutil.copytree(item, dest, ignore=shutil.ignore_patterns(*exclude_patterns))
        else:
            shutil.copy2(item, dest)
    
    archive_name = f"{package_name}.tar.gz"
    archive_path = dist_dir / archive_name
    
    shutil.make_archive(
        str(dist_dir / package_name),
        'gztar',
        root_dir=str(package_path.parent),
        base_dir=package_name
    )
    
    shutil.rmtree(package_path)
    
    with open(archive_path, 'rb') as f:
        sha256_hash = hashlib.sha256(f.read()).hexdigest()
    
    checksum_file = dist_dir / f"{archive_name}.sha256"
    with open(checksum_file, 'w') as f:
        f.write(f"{sha256_hash}  {archive_name}\n")
    
    manifest = {
        'package': archive_name,
        'version': version,
        'timestamp': timestamp,
        'sha256': sha256_hash,
        'size_bytes': archive_path.stat().st_size
    }
    
    manifest_file = dist_dir / 'manifest.json'
    with open(manifest_file, 'w') as f:
        json.dump(manifest, f, indent=2)
    
    print(f"Package created: {archive_path}")
    print(f"SHA256: {sha256_hash}")
    print(f"Size: {archive_path.stat().st_size} bytes")
    print(f"Manifest: {manifest_file}")

def main():
    print("=== CI/CD Deployment Pipeline ===\n")
    
    start_time = datetime.now()
    
    try:
        install_dependencies()
        run_tests()
        package_deployment()
        
        elapsed = (datetime.now() - start_time).total_seconds()
        print(f"\n=== Deployment Pipeline Completed Successfully in {elapsed:.2f}s ===")
        
    except subprocess.CalledProcessError as e:
        print(f"\nERROR: Pipeline failed: {e}", file=sys.stderr)
        sys.exit(1)
    except Exception as e:
        print(f"\nERROR: Unexpected error: {e}", file=sys.stderr)
        sys.exit(1)

if __name__ == '__main__':
    main()